// Parse and validate input
const body = $input.first().json.body ?? $input.first().json;

const { service_id, doctor_id, steps } = body;

if (!doctor_id) throw new Error('doctor_id is required');
if (!Array.isArray(steps) || steps.length === 0) throw new Error('steps array is required');

// Separate calendar vs manual steps
const calendarSteps = steps.filter(s => s.schedule_mode === 'calendar');
const manualSteps   = steps.filter(s => s.schedule_mode !== 'calendar');

// Pre-build the "all available" response for the no-calendar-steps case
const earlyResults = steps.map(s => ({
  step_id: s.step_id,
  status: 'available',
  alternatives: []
}));

return [{
  json: {
    service_id,
    doctor_id,
    steps,
    calendarSteps,
    manualSteps,
    hasCalendarSteps: calendarSteps.length > 0,
    earlyResults
  }
}];

// Build SQL to check appointment count per date for the doctor
const { doctor_id, calendarSteps } = $input.first().json;

// Compute the lookahead range for alternatives (7 weeks out from last step)
const dates = calendarSteps.map(s => new Date(s.scheduled_date));

const maxDate = new Date(Math.max(...dates.map(d => d.getTime())));
maxDate.setDate(maxDate.getDate() + 49);
const lookaheadEnd = maxDate.toISOString().split('T')[0];

const minDate = new Date(Math.min(...dates.map(d => d.getTime())));
minDate.setDate(minDate.getDate() - 1);
const lookaheadStart = minDate.toISOString().split('T')[0];

const conflictSQL = `
  SELECT
    start_time::date::text AS appointment_date,
    COUNT(*) AS appointment_count
  FROM appointments
  WHERE
    doctor_id = '${doctor_id}'
    AND start_time::date BETWEEN '${lookaheadStart}' AND '${lookaheadEnd}'
    AND status NOT IN ('cancelled', 'no-show')
  GROUP BY start_time::date
  ORDER BY start_time::date
`;

return [{
  json: {
    ...$input.first().json,
    lookaheadStart,
    lookaheadEnd,
    conflictSQL
  }
}];

// Merge conflict data with steps and build final response

// Get appointment counts per date from Postgres output
const pgRows = $input.all();
const countByDate = {};
pgRows.forEach(item => {
  const { appointment_date, appointment_count } = item.json;
  if (appointment_date) {
    countByDate[appointment_date] = parseInt(appointment_count, 10);
  }
});

// Retrieve original step data from Parse Input node
const parseNode = $('Parse Input').first().json;
const { steps } = parseNode;

// Max appointments per day before flagging as conflict
const CONFLICT_THRESHOLD = 5;

// Dates with availability (< threshold) — used to suggest alternatives
const availableDateSet = new Set(
  Object.entries(countByDate)
    .filter(([, cnt]) => cnt < CONFLICT_THRESHOLD)
    .map(([date]) => date)
);

// Generate next N available weekday alternatives after a given date
function getAlternatives(fromDate, n = 5) {
  const alternatives = [];
  const d = new Date(fromDate);
  let safety = 0;
  while (alternatives.length < n && safety < 90) {
    d.setDate(d.getDate() + 1);
    safety++;
    const day = d.getDay();
    if (day === 0 || day === 6) continue; // skip weekends
    const iso = d.toISOString().split('T')[0];
    // Available if in the set OR not in countByDate at all (zero appointments)
    if (availableDateSet.has(iso) || !(iso in countByDate)) {
      alternatives.push(iso);
    }
  }
  return alternatives;
}

// Build results for all steps
const results = steps.map(step => {
  if (step.schedule_mode !== 'calendar') {
    return { step_id: step.step_id, status: 'available', alternatives: [] };
  }

  const date = step.scheduled_date;
  const count = countByDate[date] ?? 0;
  const hasConflict = count >= CONFLICT_THRESHOLD;

  return {
    step_id: step.step_id,
    status: hasConflict ? 'conflict' : 'available',
    conflict_reason: hasConflict
      ? `El doctor ya tiene ${count} citas agendadas para ese día`
      : null,
    alternatives: hasConflict ? getAlternatives(date) : []
  };
});

return [{ json: { results } }];
